-- Seed CBT Practice Exams

INSERT INTO public.exams (id, title, description, slug, duration_minutes, pass_score, difficulty, instructions, sections, tags, created_at)
VALUES ('55469327-2e1e-4471-8772-98d525641d66', 'Mathematics Practice Test', 'Test your math skills with this comprehensive practice exam covering algebra, geometry, and advanced mathematics concepts.', 'mathematics-practice-test', 60, 70, 'Intermediate', '["This exam consists of 30 multiple-choice questions","You have 60 minutes to complete the exam","Each question has only one correct answer","You can navigate between questions using the sidebar or footer","Once submitted, you cannot change your answers"]', '[{"title":"Algebra","description":"Linear equations, quadratic formulas, and algebraic expressions","questions":[{"id":"q-0-0","text":"If 2x + 5 = 15, what is the value of x?","type":"multiple_choice","options":["5","10","7.5","20"],"correct_option_index":0,"points":1},{"id":"q-0-1","text":"Which of the following is a quadratic equation?","type":"multiple_choice","options":["y = 2x + 5","y = x² + 3x - 4","y = 5","y = 1/x"],"correct_option_index":1,"points":1},{"id":"q-0-2","text":"Factor completely: x² - 9","type":"multiple_choice","options":["(x - 3)(x + 3)","(x - 3)(x - 3)","(x + 3)(x + 3)","x(x - 9)"],"correct_option_index":0,"points":1},{"id":"q-0-3","text":"Solve for y: 3y - 7 = 8","type":"multiple_choice","options":["y = 5","y = 3","y = 7","y = 15"],"correct_option_index":0,"points":1},{"id":"q-0-4","text":"What is the slope of the line y = -2x + 3?","type":"multiple_choice","options":["-2","2","3","-3"],"correct_option_index":0,"points":1},{"id":"q-0-5","text":"Simplify: (3x²y³)(4x³y²)","type":"multiple_choice","options":["12x⁵y⁵","7x⁵y⁵","12x⁶y⁶","7x⁶y⁶"],"correct_option_index":0,"points":1},{"id":"q-0-6","text":"Solve the system: 2x + y = 5, x - y = 1","type":"multiple_choice","options":["x=2, y=1","x=3, y=-1","x=1, y=3","x=2, y=3"],"correct_option_index":0,"points":1},{"id":"q-0-7","text":"What is the solution to |x - 3| = 7?","type":"multiple_choice","options":["x=10 or x=-4","x=4 or x=-10","x=10","x=-4"],"correct_option_index":0,"points":1},{"id":"q-0-8","text":"Factor: x² + 5x + 6","type":"multiple_choice","options":["(x+2)(x+3)","(x+1)(x+6)","(x+2)(x+4)","(x+3)(x+3)"],"correct_option_index":0,"points":1},{"id":"q-0-9","text":"Solve: 2(x - 3) + 5 = 3(x + 1)","type":"multiple_choice","options":["x=-4","x=4","x=2","x=-2"],"correct_option_index":0,"points":1},{"id":"q-0-10","text":"What is the vertex of the parabola y = x² - 4x + 3?","type":"multiple_choice","options":["(2, -1)","(1, 0)","(4, 3)","(-2, 15)"],"correct_option_index":0,"points":1},{"id":"q-0-11","text":"Simplify: √(16x²)","type":"multiple_choice","options":["4|x|","4x","8x","16x"],"correct_option_index":0,"points":1},{"id":"q-0-12","text":"Solve for x: log₂(x) = 3","type":"multiple_choice","options":["x=8","x=6","x=9","x=4"],"correct_option_index":0,"points":1},{"id":"q-0-13","text":"What is the domain of f(x) = √(x-2)?","type":"multiple_choice","options":["x ≥ 2","x > 2","x ≤ 2","All real numbers"],"correct_option_index":0,"points":1},{"id":"q-0-14","text":"If f(x) = 2x + 3 and g(x) = x², what is f(g(2))?","type":"multiple_choice","options":["11","7","10","14"],"correct_option_index":0,"points":1}]},{"title":"Geometry","description":"Shapes, angles, areas, and volumes","questions":[{"id":"q-0-0","text":"What is the area of a circle with radius 5?","type":"multiple_choice","options":["10π","25π","50π","100π"],"correct_option_index":1,"points":1},{"id":"q-0-1","text":"In a right triangle, if the two shorter sides are 3 and 4, what is the length of the hypotenuse?","type":"multiple_choice","options":["5","6","7","8"],"correct_option_index":0,"points":1},{"id":"q-0-2","text":"What is the sum of interior angles in a pentagon?","type":"multiple_choice","options":["540°","360°","720°","180°"],"correct_option_index":0,"points":1},{"id":"q-0-3","text":"If two angles are supplementary and one is 70°, what is the other?","type":"multiple_choice","options":["110°","70°","20°","290°"],"correct_option_index":0,"points":1},{"id":"q-0-4","text":"What is the volume of a cube with side length 4?","type":"multiple_choice","options":["64","16","32","48"],"correct_option_index":0,"points":1},{"id":"q-0-5","text":"How many edges does a rectangular prism have?","type":"multiple_choice","options":["12","8","6","10"],"correct_option_index":0,"points":1},{"id":"q-0-6","text":"What is the circumference of a circle with diameter 10?","type":"multiple_choice","options":["10π","20π","25π","5π"],"correct_option_index":0,"points":1},{"id":"q-0-7","text":"If two triangles are similar and the ratio of their sides is 2:3, what is the ratio of their areas?","type":"multiple_choice","options":["4:9","2:3","1:2","3:4"],"correct_option_index":0,"points":1},{"id":"q-0-8","text":"What is the Pythagorean theorem?","type":"multiple_choice","options":["a² + b² = c²","a + b = c","a × b = c","a² - b² = c²"],"correct_option_index":0,"points":1},{"id":"q-0-9","text":"How many sides does a hexagon have?","type":"multiple_choice","options":["6","5","7","8"],"correct_option_index":0,"points":1}]},{"title":"Advanced Mathematics","description":"Calculus and trigonometry problems","questions":[{"id":"q-0-0","text":"What is the derivative of x³?","type":"multiple_choice","options":["3x²","3x","x⁴/4","x²"],"correct_option_index":0,"points":1},{"id":"q-0-1","text":"What is the integral of 2x?","type":"multiple_choice","options":["x² + C","2x² + C","x + C","2 + C"],"correct_option_index":0,"points":1},{"id":"q-0-2","text":"What is sin(π/2)?","type":"multiple_choice","options":["1","0","0.5","√2/2"],"correct_option_index":0,"points":1},{"id":"q-0-3","text":"What is the value of lim(x→0) sin(x)/x?","type":"multiple_choice","options":["1","0","∞","Undefined"],"correct_option_index":0,"points":1},{"id":"q-0-4","text":"What is the derivative of sin(x)?","type":"multiple_choice","options":["cos(x)","-cos(x)","-sin(x)","tan(x)"],"correct_option_index":0,"points":1}]}]', '["mathematics","quantitative"]', NOW())
ON CONFLICT (id) DO UPDATE SET
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    sections = EXCLUDED.sections,
    tags = EXCLUDED.tags;

INSERT INTO public.exams (id, title, description, slug, duration_minutes, pass_score, difficulty, instructions, sections, tags, created_at)
VALUES ('66469327-2e1e-4471-8772-98d525641d77', 'English Language Test', 'Assess your English grammar and comprehension skills with this comprehensive language exam.', 'english-language-test', 45, 70, 'Beginner', '["This exam consists of 25 multiple-choice questions","You have 45 minutes to complete the exam","Each question has only one correct answer","You can navigate between questions using the sidebar or footer","Once submitted, you cannot change your answers"]', '[{"title":"Grammar","description":"Sentence structure, tenses, and parts of speech","questions":[{"id":"q-1-0","text":"Choose the correct sentence:","type":"multiple_choice","options":["She don''t like apples.","She doesn''t like apples.","She isn''t like apples.","She not like apples."],"correct_option_index":1,"points":1},{"id":"q-1-1","text":"Which sentence is in the past perfect tense?","type":"multiple_choice","options":["I had finished my work when she called.","I finished my work when she called.","I have finished my work when she called.","I finish my work when she called."],"correct_option_index":0,"points":1},{"id":"q-1-2","text":"Identify the adjective: ''The quick brown fox jumps over the lazy dog.''","type":"multiple_choice","options":["Quick and brown","Fox and dog","Jumps and over","The and the"],"correct_option_index":0,"points":1},{"id":"q-1-3","text":"Choose the correctly spelled word:","type":"multiple_choice","options":["Necessary","Necesary","Neccessary","Necesarry"],"correct_option_index":0,"points":1},{"id":"q-1-4","text":"Which is a compound sentence?","type":"multiple_choice","options":["I wanted to go, but I was too tired.","Because I was tired, I didn''t go.","Going to the party tired me.","Tired from the party, I went home."],"correct_option_index":0,"points":1},{"id":"q-1-5","text":"Select the correct pronoun: ''Between you and ___ , I think we should go.''","type":"multiple_choice","options":["me","I","myself","mine"],"correct_option_index":0,"points":1},{"id":"q-1-6","text":"Which sentence uses correct punctuation?","type":"multiple_choice","options":["She said, ''I''ll be there soon.''","She said ''I''ll be there soon.''","She said, I''ll be there soon.","She said; ''I''ll be there soon.''"],"correct_option_index":0,"points":1},{"id":"q-1-7","text":"Identify the verb: ''The children played in the park.''","type":"multiple_choice","options":["played","children","park","the"],"correct_option_index":0,"points":1},{"id":"q-1-8","text":"Choose the correct form: ''There ___ many reasons for this decision.''","type":"multiple_choice","options":["are","is","be","am"],"correct_option_index":0,"points":1},{"id":"q-1-9","text":"Which is not a preposition?","type":"multiple_choice","options":["jump","under","above","through"],"correct_option_index":0,"points":1}]},{"title":"Vocabulary","description":"Word meanings, synonyms, and antonyms","questions":[{"id":"q-1-0","text":"What is a synonym for ''happy''?","type":"multiple_choice","options":["Joyful","Sad","Angry","Tired"],"correct_option_index":0,"points":1},{"id":"q-1-1","text":"What is the meaning of ''benevolent''?","type":"multiple_choice","options":["Kind-hearted","Evil","Large","Small"],"correct_option_index":0,"points":1},{"id":"q-1-2","text":"What is an antonym for ''brave''?","type":"multiple_choice","options":["Cowardly","Strong","Fearless","Heroic"],"correct_option_index":0,"points":1},{"id":"q-1-3","text":"What does ''ambiguous'' mean?","type":"multiple_choice","options":["Unclear","Clear","Happy","Sad"],"correct_option_index":0,"points":1},{"id":"q-1-4","text":"What is a synonym for ''beautiful''?","type":"multiple_choice","options":["Gorgeous","Ugly","Plain","Ordinary"],"correct_option_index":0,"points":1},{"id":"q-1-5","text":"What does ''pragmatic'' mean?","type":"multiple_choice","options":["Practical","Theoretical","Idealistic","Dreamy"],"correct_option_index":0,"points":1},{"id":"q-1-6","text":"What is an antonym for ''generous''?","type":"multiple_choice","options":["Stingy","Kind","Giving","Charitable"],"correct_option_index":0,"points":1},{"id":"q-1-7","text":"What does ''eloquent'' mean?","type":"multiple_choice","options":["Fluent and persuasive","Quiet","Rude","Simple"],"correct_option_index":0,"points":1}]},{"title":"Comprehension","description":"Reading passages and questions","questions":[{"id":"q-1-0","text":"Read the passage: ''The company decided to implement new policies to improve employee satisfaction. They introduced flexible working hours and remote work options.'' What was the company''s goal?","type":"multiple_choice","options":["Improve employee satisfaction","Increase productivity","Reduce costs","Expand to new markets"],"correct_option_index":0,"points":1},{"id":"q-1-1","text":"Based on the same passage, what changes did the company implement?","type":"multiple_choice","options":["Flexible working hours and remote work","Higher salaries and more benefits","New office location and equipment","Different management structure"],"correct_option_index":0,"points":1},{"id":"q-1-2","text":"Read: ''The research indicated that regular exercise not only improves physical health but also enhances mental well-being.'' What is the main idea?","type":"multiple_choice","options":["Exercise benefits both physical and mental health","Exercise is only good for physical health","Mental health is more important than physical health","Research is unnecessary for understanding health"],"correct_option_index":0,"points":1},{"id":"q-1-3","text":"Based on the same passage, what did the research indicate?","type":"multiple_choice","options":["Exercise improves physical and mental health","Exercise is only for young people","Mental health doesn''t matter","Research is always accurate"],"correct_option_index":0,"points":1},{"id":"q-1-4","text":"Read: ''The novel explored themes of identity, belonging, and the search for meaning in a rapidly changing world.'' What themes did the novel explore?","type":"multiple_choice","options":["Identity, belonging, and search for meaning","Love, romance, and relationships","War, peace, and conflict","Wealth, poverty, and social class"],"correct_option_index":0,"points":1},{"id":"q-1-5","text":"What was the setting described in the previous question?","type":"multiple_choice","options":["A rapidly changing world","A historical period","A fantasy realm","A scientific laboratory"],"correct_option_index":0,"points":1},{"id":"q-1-6","text":"Read: ''The experiment yielded unexpected results that challenged existing theories and opened new avenues for research.'' What did the experiment do?","type":"multiple_choice","options":["Challenged theories and opened new research avenues","Confirmed existing theories","Closed down research possibilities","Had no significant impact"],"correct_option_index":0,"points":1}]}]', '["english","language"]', NOW())
ON CONFLICT (id) DO UPDATE SET
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    sections = EXCLUDED.sections,
    tags = EXCLUDED.tags;

INSERT INTO public.exams (id, title, description, slug, duration_minutes, pass_score, difficulty, instructions, sections, tags, created_at)
VALUES ('77469327-2e1e-4471-8772-98d525641d88', 'Science Knowledge Assessment', 'Test your knowledge of basic scientific concepts across biology, physics, and chemistry.', 'science-knowledge-assessment', 75, 70, 'Advanced', '["This exam consists of 40 multiple-choice questions","You have 75 minutes to complete the exam","Each question has only one correct answer","You can navigate between questions using the sidebar or footer","Once submitted, you cannot change your answers"]', '[{"title":"Physics","description":"Mechanics, energy, electricity, and magnetism","questions":[{"id":"q-2-0","text":"What is the SI unit of force?","type":"multiple_choice","options":["Joule","Newton","Watt","Pascal"],"correct_option_index":1,"points":1},{"id":"q-2-1","text":"Which law states that for every action there is an equal and opposite reaction?","type":"multiple_choice","options":["Newton''s First Law","Newton''s Second Law","Newton''s Third Law","Law of Conservation of Energy"],"correct_option_index":2,"points":1},{"id":"q-2-2","text":"What is the speed of light in a vacuum?","type":"multiple_choice","options":["3 × 10⁸ m/s","3 × 10⁵ m/s","3 × 10¹⁰ m/s","3 × 10³ m/s"],"correct_option_index":0,"points":1},{"id":"q-2-3","text":"Which of these is a vector quantity?","type":"multiple_choice","options":["Velocity","Speed","Mass","Temperature"],"correct_option_index":0,"points":1},{"id":"q-2-4","text":"What is the formula for kinetic energy?","type":"multiple_choice","options":["½mv²","mgh","Fd","ma"],"correct_option_index":0,"points":1},{"id":"q-2-5","text":"Which material is the best conductor of electricity?","type":"multiple_choice","options":["Silver","Copper","Iron","Aluminum"],"correct_option_index":0,"points":1},{"id":"q-2-6","text":"What does E=mc² represent?","type":"multiple_choice","options":["Mass-energy equivalence","Kinetic energy","Potential energy","Thermal energy"],"correct_option_index":0,"points":1},{"id":"q-2-7","text":"Which type of lens converges light?","type":"multiple_choice","options":["Convex","Concave","Plano-concave","Diverging"],"correct_option_index":0,"points":1},{"id":"q-2-8","text":"What is the unit of electrical resistance?","type":"multiple_choice","options":["Ohm","Volt","Ampere","Watt"],"correct_option_index":0,"points":1},{"id":"q-2-9","text":"Which law states that pressure and volume are inversely proportional at constant temperature?","type":"multiple_choice","options":["Boyle''s Law","Charles''s Law","Gay-Lussac''s Law","Avogadro''s Law"],"correct_option_index":0,"points":1},{"id":"q-2-10","text":"What is the acceleration due to gravity on Earth?","type":"multiple_choice","options":["9.8 m/s²","8.9 m/s²","10 m/s²","7.6 m/s²"],"correct_option_index":0,"points":1},{"id":"q-2-11","text":"Which subatomic particle has a negative charge?","type":"multiple_choice","options":["Electron","Proton","Neutron","Photon"],"correct_option_index":0,"points":1},{"id":"q-2-12","text":"What is the principle behind a nuclear power plant?","type":"multiple_choice","options":["Nuclear fission","Nuclear fusion","Chemical reaction","Solar energy"],"correct_option_index":0,"points":1},{"id":"q-2-13","text":"Which electromagnetic waves have the highest frequency?","type":"multiple_choice","options":["Gamma rays","Radio waves","Microwaves","Visible light"],"correct_option_index":0,"points":1},{"id":"q-2-14","text":"What is the law of conservation of energy?","type":"multiple_choice","options":["Energy cannot be created or destroyed","Energy increases over time","Energy decreases over time","Energy can be created but not destroyed"],"correct_option_index":0,"points":1}]}]', '["science","biology","physics","chemistry"]', NOW())
ON CONFLICT (id) DO UPDATE SET
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    sections = EXCLUDED.sections,
    tags = EXCLUDED.tags;
